#include <stdio.h>
#include <stdlib.h>

long long gcd_ll(long long a, long long b) {
    while (b) { long long t = a % b; a = b; b = t; }
    return a < 0 ? -a : a;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long p, q, N; scanf("%lld %lld %lld", &p, &q, &N);
        long long D = p - q; // can be negative
        long long M = 12LL * q;
        long long g = gcd_ll(llabs(D), M);
        long long L = M / g; // period in hours
        long long t = (N - 1) * L; // total elapsed hours
        long long day = t / 24 + 1;
        printf("%lld\n", day);
    }
    return 0;
}

